/**
 * Solves the problem by maintaining connected components and the parity of path weights
 * within each component using a Disjoint Set Union (DSU) structure augmented with path parity tracking.
 * 
 * @param {number} n The number of nodes (0 to n-1).
 * @param {number[][]} edges An array of edges [u, v, w].
 * @returns {number} The count of successfully added edges.
 */
function solve(n, edges) {
    // parent[i]: stores the parent of node i
    const parent = Array(n).fill(0).map((_, i) => i);
    // parity_dist[i]: stores the parity of the path weight from node i to its current representative (parent[i])
    const parity_dist = Array(n).fill(0);

    // Helper function to find the root of node i, applying path compression and updating parity distance.
    // Returns [root, distance_to_root]
    function find(i) {
        if (parent[i] === i) {
            return [i, 0];
        }

        // Recursively find the root and the distance of the parent to that root
        const [root, dist_parent_to_root] = find(parent[i]);

        // Update distance: distance(i -> root) = distance(i -> parent) XOR distance(parent -> root)
        parity_dist[i] = parity_dist[i] ^ dist_parent_to_root;

        // Path compression
        parent[i] = root;

        return [root, parity_dist[i]];
    }

    let added_edge_count = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        // Step 1: Find representatives and distances
        const [root_u, dist_u] = find(u);
        const [root_v, dist_v] = find(v);

        if (root_u !== root_v) {
            // Case 1: Different components. Adding the edge is always valid as no cycles are created.
            added_edge_count++;

            // Merge root_v into root_u (assuming union by rank/size isn't strictly necessary for correctness, just efficiency)
            parent[root_v] = root_u;

            // Calculate the new parity distance for root_v to root_u.
            // Path: root_v --(dist_v)--> v --(w)--> u --(dist_u)--> root_u
            // New parity_dist[root_v] = dist_v XOR w XOR dist_u
            parity_dist[root_v] = dist_v ^ w ^ dist_u;

        } else {
            // Case 2: Same component. Adding the edge creates a cycle. Check parity condition.

            // Path u -> v in existing graph has parity: dist_u XOR dist_v
            // Cycle weight = w XOR (dist_u XOR dist_v)
            // Condition for validity: Cycle weight must be 0 (even).
            // Required: w XOR dist_u XOR dist_v = 0

            if ((w ^ dist_u ^ dist_v) === 0) {
                // Condition met: The cycle has even weight. Add the edge.
                added_edge_count++;
                // No DSU update needed as the connectivity structure remains the same.
            } 
            // Else: Condition failed, discard the edge.
        }
    }

    return added_edge_count;
}

