type DSU struct {
	parent      []int64
	// parity_dist[i] stores the parity of the path weight from i to parent[i]
	// Since weights are 0 or 1, this is equivalent to XOR sum.
	parity_dist []int64
}

func NewDSU(n int64) *DSU {
	parent := make([]int64, n)
	parity_dist := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		parity_dist[i] = 0
	}
	return &DSU{parent: parent, parity_dist: parity_dist}
}

// Find returns [root, distance_to_root]
// distance_to_root is the parity of the path from i to root.
func (d *DSU) Find(i int64) (int64, int64) {
	if d.parent[i] == i {
		return i, 0
	}

	// Recursively find the root and the distance of the parent to that root
	root, distParentToRoot := d.Find(d.parent[i])

	// Update distance: distance(i -> root) = distance(i -> parent) XOR distance(parent -> root)
	// d.parity_dist[i] currently holds distance(i -> parent[i])
	d.parity_dist[i] = d.parity_dist[i] ^ distParentToRoot

	// Path compression
	d.parent[i] = root

	return root, d.parity_dist[i]
}

// Union attempts to add the edge (u, v) with weight w.
// Returns true if the edge is successfully added, false otherwise.
func (d *DSU) Union(u, v, w int64) bool {
	rootU, distU := d.Find(u)
	rootV, distV := d.Find(v)

	if rootU != rootV {
		// Case 1: Different components. Always add the edge.

		// Merge V into U
		d.parent[rootV] = rootU

		// Calculate the new parity distance for rootV to rootU.
		// Path: rootV --(distV)--> v --(w)--> u --(distU)--> rootU
		// New parity_dist[rootV] = distV XOR w XOR distU
		d.parity_dist[rootV] = distV ^ w ^ distU

		return true
	} else {
		// Case 2: Same component. Adding the edge creates a cycle. Check parity condition.

		// The existing path parity between u and v is distU XOR distV.
		// Cycle weight = w XOR (existing path parity)
		cycleParity := w ^ distU ^ distV

		if cycleParity == 0 {
			// Condition met: The cycle has even weight. Add the edge.
			return true
		} else {
			// Condition failed: The cycle has odd weight. Discard the edge.
			return false
		}
	}
}

func solve(n int64, edges [][]int64) int64 {
	dsu := NewDSU(n)
	addedEdgeCount := int64(0)

	for _, edge := range edges {
		u := edge[0]
		v := edge[1]
		w := edge[2]

		if dsu.Union(u, v, w) {
			addedEdgeCount++
		}
	}

	return addedEdgeCount
}
